export function $(selector,context=document){return context.querySelector(selector);}export function $$(selector,context=document){return Array.from(context.querySelectorAll(selector));}export function createElement(tag,attributes={},content=''){const el=document.createElement(tag);Object.entries(attributes).forEach(([key,value])=>{if(key.startsWith('data-')){el.setAttribute(key,value);}else if(key==='class'){el.className=value;}else if(key.startsWith('on')){el.addEventListener(key.slice(2).toLowerCase(),value);}else{el.setAttribute(key,value);}});if(content){if(typeof content==='string'){el.textContent=content;}else if(content instanceof Element){el.appendChild(content);}}return el;}export function setHTML(element,html,options={}){const{sanitize=false}=options;if(!sanitize){element.innerHTML=html;return;}const sanitized=html .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi,'').replace(/on\w+="[^"]*"/g,'');element.innerHTML=sanitized;}export function removeElement(element){if(element&&element.parentNode){element.remove();}}